-- Program: Obese to Active
-- Category: Body-Specific -> body_specific
-- Priority: low
-- Durations: [8, 12, 16], Sessions: [3, 4]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Obese to Active',
    'Progressive mobility building for individuals with obesity. Graduates from seated exercises to standing movements to light resistance over time.',
    'body_specific',
    'all_levels',
    16,
    4,
    'flow',
    ARRAY['Improve flexibility', 'Enhance body awareness']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Obese to Active - 8w 3x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    8,
    'Obese to Active - 8w 3x/wk',
    'body_specific',
    3,
    60,
    ARRAY['Improve flexibility', 'Enhance body awareness']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Obese to Active'
ON CONFLICT DO NOTHING;

